import logo from "./logo.svg";
import hT_DESIGN from "./img_heroTitle01.png";
import hT_CODE from "./img_heroTitle02.png";
import hT_PUBLISHING from "./img_heroTitle03.png";
import profile_Img from "./img_profile.png";
import parentheses from "./img_parentheses.svg";
import web_pablo from "./img_web_pablo.png";
import web_lp from "./img_web_lp.png";
import web_book from "./img_web_book.png";

export { logo };

export const heroTitle = {
  hT_DESIGN,
  hT_CODE,
  hT_PUBLISHING
};

export const profileImg = {
  profile_Img,
  parentheses
};

export const projectImg = {
  web_pablo,
  web_lp,
  web_book
};
